const path = require('path');
const { createRequire } = require('node:module');

const { resolveWebpackAliases } = require('nordic-babel-alias-resolver');

const { NORDIC_DIR_PATH } = require('../constants/manifest');

const aliasesEntries = Object.entries(resolveWebpackAliases() || {});

/**
 * Check if a path has an alias
 * @param {string} filePath - The path to check
 * @param {string} alias - The alias to check
 * @example
 * checkIfPathHasAnyAlias('@components/Button', '@components') returns true
 * checkIfPathHasAnyAlias('src/components/Button', '@components') returns false
 */
const checkIfPathHasAnyAlias = (filePath, alias) =>
  filePath === alias || filePath.startsWith(`${alias}/`);

/**
 * Check if a path is an alias
 * @param {string} filePath - The path to check
 * @example
 * pathHasAlias('@components/Button') returns true
 * pathHasAlias('src/components/Button') returns false
 */
const pathHasAlias = (filePath) =>
  aliasesEntries.some(([alias]) => checkIfPathHasAnyAlias(filePath, alias));

/**
 * Get the file path from an alias
 * @param {string} aliasPath - The path with the alias
 * @param {string} dir - Absolute path to the directory where the alias is being used
 * @example
 * if @components is an alias for /app-root/app/components
 * getFilePathFromAlias('@components/Button', '/app-root/app/nordic-pages/page')
 * returns '../../components/Button'
 */
const getFilePathFromAlias = (aliasPath, dir) => {
  const aliasEntry = aliasesEntries.find(([aliasKey]) =>
    checkIfPathHasAnyAlias(aliasPath, aliasKey),
  );

  if (!aliasEntry) {
    return aliasPath;
  }

  const [alias, value] = aliasEntry;

  const resolvedPath =
    value.find?.((pathValue) => !pathValue.match(NORDIC_DIR_PATH)) || value;

  return path.relative(dir, aliasPath.replace(alias, resolvedPath));
};

/**
 * Get the file path from a Node.js subpath import
 * @param {string} subpathImport - Subpath import specifier (e.g. '#components/Button')
 * @param {string} dir - Absolute path to the directory where the import is being used
 * @example
 * if package.json has "imports": { "#components/*": "./app/components/*.jsx" }
 * getFilePathFromSubpathImport('#components/Button', '/app-root/app/nordic-pages/page')
 * returns '/app-root/app/components/Button.jsx'
 */
const getFilePathFromSubpathImport = (subpathImport, dir) => {
  try {
    return createRequire(path.join(dir, '_')).resolve(subpathImport);
  } catch (error) {
    throw new Error(
      `Failed to resolve subpath import "${subpathImport}" from "${dir}"`,
      { cause: error },
    );
  }
};

module.exports = {
  pathHasAlias,
  getFilePathFromAlias,
  getFilePathFromSubpathImport,
};
